(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>\"]/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"binomial-probability",fields:[{"key":"trials","label":"시행 횟수 n","type":"integer","placeholder":"","default":"","options":[],"raw":false},{"key":"successes","label":"성공 횟수 k","type":"integer","placeholder":"","default":"","options":[],"raw":false},{"key":"probability","label":"1회 성공확률 (0~1)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var n=Number(x.trials),k=Number(x.successes),p=Number(x.probability);if(![n,k,p].every(Number.isFinite)||!Number.isInteger(n)||!Number.isInteger(k)||n<0||k<0||k>n||p<0||p>1)return{error:"n과 k는 조건에 맞는 정수, 확률은 0~1로 입력해 주세요."};function comb(a,b){b=Math.min(b,a-b);var r=1;for(var i=1;i<=b;i++)r=r*(a-b+i)/i;return r;}var pr=comb(n,k)*Math.pow(p,k)*Math.pow(1-p,n-k);return{probability:pr,percent:pr*100,expectedSuccesses:n*p};},format:function(r,api){return api.resultCard("정확히 k회 성공확률",api.formatNumber(r.probability,10),api.formatNumber(r.percent,6)+"%")+api.resultCard("기대 성공횟수",api.formatNumber(r.expectedSuccesses,3)+"회","");}},{id:"expected-value-discrete",fields:[{"key":"values","label":"값 목록","type":"textarea","placeholder":"예: 0, 10, 20","default":"","options":[],"raw":true},{"key":"probabilities","label":"확률 목록","type":"textarea","placeholder":"예: 0.2, 0.5, 0.3","default":"","options":[],"raw":true}],hint:"",compute:function(x){function arr(v){return String(v||"").split(/[\s,;]+/).filter(Boolean).map(Number);}var a=arr(x.values),p=arr(x.probabilities);if(!a.length||a.length!==p.length||a.some(function(v){return !Number.isFinite(v);})||p.some(function(v){return !Number.isFinite(v)||v<0;}))return{error:"값과 확률을 같은 개수로 올바르게 입력해 주세요."};var sum=p.reduce(function(s,v){return s+v;},0);if(Math.abs(sum-1)>1e-6)return{error:"확률의 합이 1이 되도록 입력해 주세요."};var ev=a.reduce(function(s,v,i){return s+v*p[i];},0);var variance=a.reduce(function(s,v,i){return s+Math.pow(v-ev,2)*p[i];},0);return{expectedValue:ev,variance:variance,standardDeviation:Math.sqrt(variance),probabilitySum:sum};},format:function(r,api){return api.resultCard("기댓값",api.formatNumber(r.expectedValue,6),"")+api.resultCard("표준편차",api.formatNumber(r.standardDeviation,6),"분산 "+api.formatNumber(r.variance,6));}},{id:"confidence-interval-mean",fields:[{"key":"sampleMean","label":"표본평균","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"sampleSd","label":"표본 표준편차","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"sampleSize","label":"표본 수","type":"integer","placeholder":"","default":"","options":[],"raw":false},{"key":"confidence","label":"신뢰수준","type":"select","placeholder":"","default":"95","options":[[90,"90%"],[95,"95%"],[99,"99%"]],"raw":true}],hint:"정규근사 기반 참고값입니다. 작은 표본은 t분포가 더 적절할 수 있습니다.",compute:function(x){var m=Number(x.sampleMean),s=Number(x.sampleSd),n=Number(x.sampleSize),c=Number(x.confidence);if(![m,s,n,c].every(Number.isFinite)||s<0||!Number.isInteger(n)||n<=1)return{error:"표준편차는 0 이상, 표본 수는 2 이상 정수로 입력해 주세요."};var z=c===90?1.64485362695147:c===99?2.5758293035489:1.95996398454005;var se=s/Math.sqrt(n),margin=z*se;return{standardError:se,margin:margin,lower:m-margin,upper:m+margin};},format:function(r,api){return api.resultCard("평균 신뢰구간",api.formatNumber(r.lower,6)+" ~ "+api.formatNumber(r.upper,6),"오차한계 ±"+api.formatNumber(r.margin,6))+api.resultCard("표준오차",api.formatNumber(r.standardError,6),"");}},{id:"resistor-voltage-divider",fields:[{"key":"inputVoltage","label":"입력전압 (V)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"r1Ohm","label":"R1 (Ω)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"r2Ohm","label":"R2 (Ω)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var v=Number(x.inputVoltage),a=Number(x.r1Ohm),b=Number(x.r2Ohm);if(![v,a,b].every(Number.isFinite)||a<=0||b<=0)return{error:"저항값은 0보다 크게 입력해 주세요."};var i=v/(a+b),out=v*b/(a+b);return{outputVoltage:out,currentAmp:i,totalResistance:a+b,powerTotal:v*i};},format:function(r,api){return api.resultCard("출력전압",api.formatNumber(r.outputVoltage,6)+"V","전류 "+api.formatNumber(r.currentAmp,9)+"A")+api.resultCard("총 소비전력",api.formatNumber(r.powerTotal,6)+"W","");}},{id:"ac-rms-peak",fields:[{"key":"rmsVoltage","label":"RMS 전압 (V)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"정현파 기준입니다.",compute:function(x){var r=Number(x.rmsVoltage);if(!Number.isFinite(r)||r<0)return{error:"RMS 전압은 0 이상으로 입력해 주세요."};var peak=r*Math.SQRT2;return{rms:r,peak:peak,peakToPeak:peak*2};},format:function(r,api){return api.resultCard("피크 전압",api.formatNumber(r.peak,6)+"V","RMS "+api.formatNumber(r.rms,6)+"V")+api.resultCard("피크투피크",api.formatNumber(r.peakToPeak,6)+"Vpp","");}},{id:"pipe-flow-rate",fields:[{"key":"diameterMm","label":"관 내경 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"velocityMps","label":"평균 유속 (m/s)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var d=Number(x.diameterMm),v=Number(x.velocityMps);if(![d,v].every(Number.isFinite)||d<=0||v<0)return{error:"관 내경은 0보다 크게, 유속은 0 이상으로 입력해 주세요."};var area=Math.PI*Math.pow(d/1000,2)/4,q=area*v;return{areaM2:area,flowM3s:q,flowLitersSecond:q*1000,flowM3Hour:q*3600};},format:function(r,api){return api.resultCard("유량",api.formatNumber(r.flowLitersSecond,6)+"L/s",api.formatNumber(r.flowM3Hour,6)+"m³/h")+api.resultCard("관 단면적",api.formatNumber(r.areaM2,9)+"m²","");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
